import axios from 'axios';

const api = axios.create({
  baseURL: '/api/v1',
  timeout: 10000,
});

api.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

export const ep_001 = async (params?: any) => {
  return api.{post}(`/api/v1/auth/login`, params);
};

export const ep_002 = async (params?: any) => {
  return api.{post}(`/api/v1/auth/register`, params);
};

export const ep_003 = async (params?: any) => {
  return api.{get}(`/api/v1/users/me`, params);
};

export const ep_004 = async (params?: any) => {
  return api.{put}(`/api/v1/users/me`, params);
};

export const ep_005 = async (params?: any) => {
  return api.{get}(`/api/v1/users`, params);
};

export const ep_006 = async (params?: any) => {
  return api.{get}(`/api/v1/roles`, params);
};

export const ep_007 = async (params?: any) => {
  return api.{post}(`/api/v1/roles`, params);
};

export const ep_008 = async (params?: any) => {
  return api.{get}(`/api/v1/operation-logs`, params);
};


export default api;

export interface User {
  id: number;
  username: string;
  email: string;
  phone?: string;
  status: number;
}

export interface ApiResponse<T> {
  code: number;
  message: string;
  data: T;
}

export const API_ENDPOINTS = [
  {
    "id": "EP-001",
    "method": "POST",
    "path": "/api/v1/auth/login",
    "summary": "用户登录"
  },
  {
